INSERT INTO public.designation_statements (occupation_serial, occupation_title, occupation_description, statement_serial, statement) VALUES
  (56, 'שירותי IT ותמיכה טכנית', 'תמיכה טכנית, ניהול תשתיות IT, שירותי מחשוב, פתרונות טכנולוגיים לארגונים ופרטיים', 1, 'לספק תמיכה טכנית מהירה ומקצועית למשתמשים.'),
  (56, 'שירותי IT ותמיכה טכנית', 'תמיכה טכנית, ניהול תשתיות IT, שירותי מחשוב, פתרונות טכנולוגיים לארגונים ופרטיים', 2, 'לפתור תקלות תוכנה וחומרה ביעילות.'),
  (56, 'שירותי IT ותמיכה טכנית', 'תמיכה טכנית, ניהול תשתיות IT, שירותי מחשוב, פתרונות טכנולוגיים לארגונים ופרטיים', 3, 'לייעל תשתיות מחשוב בארגונים.'),
  (56, 'שירותי IT ותמיכה טכנית', 'תמיכה טכנית, ניהול תשתיות IT, שירותי מחשוב, פתרונות טכנולוגיים לארגונים ופרטיים', 4, 'לנהל רשתות תקשורת מורכבות.'),
  (56, 'שירותי IT ותמיכה טכנית', 'תמיכה טכנית, ניהול תשתיות IT, שירותי מחשוב, פתרונות טכנולוגיים לארגונים ופרטיים', 5, 'לפתח מערכות ניהול IT מותאמות ללקוח.'),
  (56, 'שירותי IT ותמיכה טכנית', 'תמיכה טכנית, ניהול תשתיות IT, שירותי מחשוב, פתרונות טכנולוגיים לארגונים ופרטיים', 6, 'לאמן צוותי עובדים בשימוש נכון במערכות IT.'),
  (56, 'שירותי IT ותמיכה טכנית', 'תמיכה טכנית, ניהול תשתיות IT, שירותי מחשוב, פתרונות טכנולוגיים לארגונים ופרטיים', 7, 'לפתח פתרונות אבטחת מידע מתקדמים.'),
  (56, 'שירותי IT ותמיכה טכנית', 'תמיכה טכנית, ניהול תשתיות IT, שירותי מחשוב, פתרונות טכנולוגיים לארגונים ופרטיים', 8, 'ליצור תהליכי גיבוי ושחזור נתונים.'),
  (56, 'שירותי IT ותמיכה טכנית', 'תמיכה טכנית, ניהול תשתיות IT, שירותי מחשוב, פתרונות טכנולוגיים לארגונים ופרטיים', 9, 'לייעץ על יישום טכנולוגיות ענן בארגונים.'),
